using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<ModelTrainingService>();

var modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");

// Train the model on startup if no saved model exists
if (!File.Exists(modelPath))
{
    var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
    using var loggerFactory = LoggerFactory.Create(b => b.AddConsole());
    var trainer = new ModelTrainingService(loggerFactory.CreateLogger<ModelTrainingService>());
    trainer.TrainAndSaveModel(dataPath, modelPath);
}

builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath, watchForChanges: true);

var app = builder.Build();
app.MapControllers();
app.Run();

