using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainingService
{
    private readonly MLContext _mlContext = new(seed: 42);
    private readonly ILogger<ModelTrainingService> _logger;

    public ModelTrainingService(ILogger<ModelTrainingService> logger)
    {
        _logger = logger;
    }

    public string TrainAndSaveModel(string dataPath, string modelPath)
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeatures", nameof(TicketInput.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        var report = FormatMetrics(metrics);
        _logger.LogInformation("Evaluation metrics:\n{Metrics}", report);

        _mlContext.Model.Save(model, split.TrainSet.Schema, modelPath);
        _logger.LogInformation("Model saved to {Path}", modelPath);

        return report;
    }

    private static string FormatMetrics(
        Microsoft.ML.Data.MulticlassClassificationMetrics m)
    {
        return $"""
            ╔══════════════════════════════════════╗
            ║     Multiclass Classification        ║
            ╠══════════════════════════════════════╣
            ║  MacroAccuracy:   {m.MacroAccuracy:F4}            ║
            ║  MicroAccuracy:   {m.MicroAccuracy:F4}            ║
            ║  LogLoss:         {m.LogLoss:F4}            ║
            ║  LogLossReduction:{m.LogLossReduction:F4}            ║
            ╚══════════════════════════════════════╝
            Per-class log-loss: {string.Join(", ", m.PerClassLogLoss.Select((v, i) => $"Class{i}={v:F4}"))}
            """;
    }
}

