using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<ModelTrainingService>();

var modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");

// Train the model on startup if no saved model exists
if (!File.Exists(modelPath))
{
    using var loggerFactory = LoggerFactory.Create(b => b.AddConsole());
    var trainer = new ModelTrainingService(loggerFactory.CreateLogger<ModelTrainingService>());
    trainer.TrainAndSaveModel(dataPath, modelPath);
}

// Extract ordered label names from the trained model's Score column
var mlContext = new MLContext(seed: 42);
var model = mlContext.Model.Load(modelPath, out var schema);
var outputSchema = model.GetOutputSchema(schema);
var scoreColumn = outputSchema["Score"];
var slotNames = new VBuffer<ReadOnlyMemory<char>>();
scoreColumn.GetSlotNames(ref slotNames);
var labelNames = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
builder.Services.AddSingleton(new LabelNames(labelNames));

builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath, watchForChanges: true);

var app = builder.Build();
app.MapControllers();
app.Run();

